+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+export class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: number = 2;
+  minLevel: number = 2;
+  maxLevel: number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {
+  level: number,
+  text: string,
+  label: string,
+  anchor: string,
+};
+
+const tocStartRegex = /<!--\\s*toc\\s*-->/gi;
+const tocEndRegex = /<!--\\s*\\/toc\\s*-->/gi;
+const atxHeadingRegex = /^(?: {0,3})(#{1,6})(?:[ \	]+(.*)|[ \	]*)$/;
+
+function removeTrailingHeadingHashes(text: string): string {
+  return text.replace(/[ \	]+#+[ \	]*$/, '').trim();
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[\\s\\S]*?\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display: string | undefined) => display ?? target)
+      .replace(/\\[([^\\]]+)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return resolveLinks(text)
+      .replace(/<[^>]*>/g, '')
+      .replace(/[\\\\`*_~=]/g, '');
+}
+
+function headingAnchor(text: string): string {
+  return stripFormatting(text)
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  return exclusions.some((exclusion) => {
+    const match = exclusion.match(/^\\/(.*)\\/$/);
+    if (match) {
+      try {
+        return new RegExp(match[1], 'i').test(text);
+      } catch (_error) {
+        // An invalid regular expression is treated as a literal heading.
+      }
+    }
+
+    return exclusion.toLowerCase() === text.toLowerCase();
+  });
+}
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.math, IgnoreTypes.yaml],
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const startMatch = tocStartRegex.exec(text);
+    if (!startMatch) {
+      return text;
+    }
+
+    tocEndRegex.lastIndex = startMatch.index + startMatch[0].length;
+    const endMatch = tocEndRegex.exec(text);
+    const tocEnd = endMatch?.index ?? text.length;
+    const headings = this.getHeadings(text, options, startMatch.index, tocEnd);
+    const toc = this.buildToc(headings, options);
+    const before = text.slice(0, startMatch.index + startMatch[0].length);
+    const endMarker = endMatch?.[0] ?? '<!-- /toc -->';
+    const after = endMatch ? text.slice(endMatch.index + endMatch[0].length).replace(/^\\s*\
?/, '') : '';
+    const body = [options.title, toc].filter((section) => section !== '').join('\
\
');
+
+    return before + '\
\
' + body + (body ? '\
\
' : '') + endMarker + '\
\
' + after;
+  }
+
+  private getHeadings(text: string, options: AutoTocOptions, tocStart: number, tocEnd: number): Heading[] {
+    const anchors = new Map<string, number>();
+    const headings: Heading[] = [];
+    let offset = 0;
+
+    for (const line of text.split('\
')) {
+      const lineEnd = offset + line.length;
+      if (lineEnd < tocStart || offset > tocEnd) {
+        const match = line.match(atxHeadingRegex);
+        if (match) {
+          const level = match[1].length;
+          let text = removeTrailingHeadingHashes(match[2] ?? '');
+          const explicitId = text.match(/\\s*\\{#([^\\s}]+)\\}\\s*$/);
+          if (explicitId && options.useExplicitIds) {
+            text = text.slice(0, explicitId.index).trimEnd();
+          }
+          const plainText = stripFormatting(text);
+
+          if (level >= options.minLevel && level <= options.maxLevel && !isExcluded(plainText, options.excludeHeadings)) {
+            const baseAnchor = explicitId && options.useExplicitIds ? explicitId[1] : headingAnchor(text);
+            const count = anchors.get(baseAnchor) ?? 0;
+            anchors.set(baseAnchor, count + 1);
+            headings.push({
+              level,
+              text,
+              label: options.stripFormattingInToc ? plainText : text,
+              anchor: count === 0 ? baseAnchor : `${baseAnchor}-${count}`,
+            });
+          }
+        }
+      }
+      offset = lineEnd + 1;
+    }
+
+    return headings;
+  }
+
+  private buildToc(headings: Heading[], options: AutoTocOptions): string {
+    return headings.map((heading, index) => {
+      const indent = ' '.repeat(Math.max(0, heading.level - options.minLevel) * options.indentSize);
+      const marker = options.listStyle === 'bullet' ? options.bulletMarker : `${options.orderedListStyle === 'increment' ? index + 1 : 1}.`;
+      return `${indent}${marker} [${heading.label}](#${heading.anchor})`;
+    }).join('\
');
+  }
+
+  get exampleBuilders(): ExampleBuilder<AutoTocOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Creates a table of contents when a TOC marker is present',
+        before: dedent`
+          # Note
+
+          <!-- toc -->
+
+          <!-- /toc -->
+
+          ## First section
+          ### Nested section
+        `,
+        after: dedent`
+          # Note
+
+          <!-- toc -->
+
+          - [First section](#first-section)
+            - [Nested section](#nested-section)
+
+          <!-- /toc -->
+
+          ## First section
+          ### Nested section
+        `,
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<AutoTocOptions>[] {
+    return [
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.list-style.name', descriptionKey: 'rules.auto-toc.list-style.description', optionsKey: 'listStyle', records: [{value: 'bullet', description: 'Use a bullet list'}, {value: 'number', description: 'Use a numbered list'}]}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.bullet-marker.name', descriptionKey: 'rules.auto-toc.bullet-marker.description', optionsKey: 'bulletMarker'}),
+      new DropdownOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.ordered-list-style.name', descriptionKey: 'rules.auto-toc.ordered-list-style.description', optionsKey: 'orderedListStyle', records: [{value: 'always-one', description: 'Use 1. for every item'}, {value: 'increment', description: 'Increment every item'}]}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.indent-size.name', descriptionKey: 'rules.auto-toc.indent-size.description', optionsKey: 'indentSize'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.min-level.name', descriptionKey: 'rules.auto-toc.min-level.description', optionsKey: 'minLevel'}),
+      new NumberOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.max-level.name', descriptionKey: 'rules.auto-toc.max-level.description', optionsKey: 'maxLevel'}),
+      new TextOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.title.name', descriptionKey: 'rules.auto-toc.title.description', optionsKey: 'title'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
